import express from 'express';
import { body, validationResult } from 'express-validator';
import jwt from 'jsonwebtoken';
import { pool } from '../db.js';
import { logger } from '../logger.js';

const router = express.Router();

// Middleware para autenticação JWT
function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];
  if (!token) return res.status(401).json({ message: 'Token não fornecido' });

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) {
      logger.warn({ message: 'Token inválido', error: err.message });
      return res.status(403).json({ message: 'Token inválido' });
    }
    req.user = user;
    next();
  });
}

/**
 * POST /api/phrases/rating
 * Recebe avaliação da frase pelo usuário autenticado.
 */
router.post(
  '/rating',
  authenticateToken,
  body('phraseId').isUUID().withMessage('phraseId deve ser UUID válido'),
  body('rating')
    .isInt({ min: 0, max: 5 })
    .withMessage('rating deve ser inteiro entre 0 e 5'),
  async (req, res) => {
    const correlationId = req.headers['x-correlation-id'] || '';
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      logger.warn({
        message: 'Validação falhou na avaliação de frase',
        errors: errors.array(),
        userId: req.user.id,
        correlationId
      });
      return res.status(400).json({ errors: errors.array() });
    }

    const { phraseId, rating } = req.body;
    const userId = req.user.id;

    try {
      const queryText = `
        INSERT INTO phrase_ratings (user_id, phrase_id, rating, created_at)
        VALUES ($1, $2, $3, NOW())
        ON CONFLICT (user_id, phrase_id) DO UPDATE SET rating = EXCLUDED.rating, created_at = NOW()
        RETURNING *;
      `;

      const result = await pool.query(queryText, [userId, phraseId, rating]);

      logger.info({
        message: 'Avaliação de frase armazenada',
        userId,
        phraseId,
        rating,
        correlationId
      });

      return res.status(200).json({ message: 'Avaliação registrada com sucesso' });
    } catch (error) {
      logger.error({
        message: 'Erro ao armazenar avaliação de frase',
        error: error.message,
        userId,
        phraseId,
        correlationId
      });
      return res.status(500).json({ message: 'Erro interno do servidor' });
    }
  }
);

export default router;

import { Pool } from 'pg';

export const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  ssl: process.env.NODE_ENV === 'production' ? { rejectUnauthorized: false } : false
});

import pino from 'pino';

export const logger = pino({
  level: process.env.LOG_LEVEL || 'info',
  base: null,
  timestamp: pino.stdTimeFunctions.isoTime
});

import { v4 as uuidv4 } from 'uuid';

export function correlationIdMiddleware(req, res, next) {
  const correlationId = req.headers['x-correlation-id'] || uuidv4();
  req.headers['x-correlation-id'] = correlationId;
  res.setHeader('X-Correlation-ID', correlationId);
  next();
}

import React, { useState } from 'react';

/**
 * Componente para avaliação de frase com nota de 0 a 5.
 * @param {string} phraseId - ID da frase avaliada
 * @param {function} onRatingSubmitted - Callback após submissão
 */
export function PhraseRating({ phraseId, onRatingSubmitted }) {
  const [rating, setRating] = useState(null);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState(null);

  const handleChange = (e) => {
    const value = parseInt(e.target.value, 10);
    if (value >= 0 && value <= 5) {
      setRating(value);
      setError(null);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (rating === null) {
      setError('Por favor, selecione uma nota entre 0 e 5');
      return;
    }
    setSubmitting(true);
    setError(null);

    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('Usuário não autenticado');
        setSubmitting(false);
        return;
      }

      const response = await fetch('/api/phrases/rating', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({ phraseId, rating })
      });

      if (!response.ok) {
        const data = await response.json();
        setError(data.message || 'Erro ao enviar avaliação');
        setSubmitting(false);
        return;
      }

      setSubmitting(false);
      if (onRatingSubmitted) onRatingSubmitted(rating);
    } catch (err) {
      setError('Erro de rede ao enviar avaliação');
      setSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} aria-label="Avaliar frase">
      <fieldset>
        <legend>Avalie a frase (0 a 5):</legend>
        {[0, 1, 2, 3, 4, 5].map((num) => (
          <label key={num} htmlFor={`rating-${num}`}>
            <input
              type="radio"
              id={`rating-${num}`}
              name="rating"
              value={num}
              checked={rating === num}
              onChange={handleChange}
              disabled={submitting}
              aria-checked={rating === num}
            />
            {num}
          </label>
        ))}
      </fieldset>
      <button type="submit" disabled={submitting} aria-disabled={submitting}>
        {submitting ? 'Enviando...' : 'Enviar Avaliação'}
      </button>
      {error && <p role="alert" style={{ color: 'red' }}>{error}</p>}
    </form>
  );
}

